INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Landmine_180s','Landmine 180''s','abdominales',ARRAY['glúteos','espalda baja','hombros'],'barra','strength',ARRAY['Position a bar into a landmine or securely anchor it in a corner. Load the bar to an appropriate weight.','Raise the bar from the floor, taking it to shoulder height with both hands with your arms extended in front of you. Adopt a wide stance. This will be your starting position.','Perform the movement by rotating the trunk and hips as you swing the weight all the way down to one side. Keep your arms extended throughout the exercise.','Reverse the motion to swing the weight all the way to the opposite side.','Continue alternating the movement until the set is complete.'],'Position a bar into a landmine or securely anchor it in a corner. Load the bar to an appropriate weight. Raise the bar from the floor, taking it to shoulder height with both hands with your arms extended in front of you. Adopt a wide stance. This will be your starting position. Perform the movement by rotating the trunk and hips as you swing the weight all the way down to one side. Keep your arms extended throughout the exercise. Reverse the motion to swing the weight all the way to the opposite side. Continue alternating the movement until the set is complete.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Landmine_180s/0.jpg','exercisedb',true),('Landmine_Linear_Jammer','Landmine Linear Jammer','hombros',ARRAY['abdominales','pantorrillas','pecho','isquiotibiales','cuádriceps','tríceps'],'barra','strength',ARRAY['Position a bar into landmine or, lacking one, securely anchor it in a corner. Load the bar to an appropriate weight and position the handle attachment on the bar.','Raise the bar from the floor, taking the handles to your shoulders. This will be your starting position.','In an athletic stance, squat by flexing your hips and setting your hips back, keeping your arms flexed.','Reverse the motion by powerfully extending through the hips, knees, and ankles, while also extending the elbows to straighten the arms. This movement should be done explosively, coming out of the squat to full extension as powerfully as possible.','Return to the starting position.'],'Position a bar into landmine or, lacking one, securely anchor it in a corner. Load the bar to an appropriate weight and position the handle attachment on the bar. Raise the bar from the floor, taking the handles to your shoulders. This will be your starting position. In an athletic stance, squat by flexing your hips and setting your hips back, keeping your arms flexed. Reverse the motion by powerfully extending through the hips, knees, and ankles, while also extending the elbows to straighten the arms. This movement should be done explosively, coming out of the squat to full extension as powerfully as possible. Return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Landmine_Linear_Jammer/0.jpg','exercisedb',true),('Lateral_Bound','Lateral Bound','aductores',ARRAY['abductores','pantorrillas','glúteos','isquiotibiales','cuádriceps'],'peso corporal','plyometrics',ARRAY['Assume a half squat position facing 90 degrees from your direction of travel. This will be your starting position.','Allow your lead leg to do a countermovement inward as you shift your weight to the outside leg.','Immediately push off and extend, attempting to bound to the side as far as possible.','Upon landing, immediately push off in the opposite direction, returning to your original start position.','Continue back and forth for several repetitions.'],'Assume a half squat position facing 90 degrees from your direction of travel. This will be your starting position. Allow your lead leg to do a countermovement inward as you shift your weight to the outside leg. Immediately push off and extend, attempting to bound to the side as far as possible. Upon landing, immediately push off in the opposite direction, returning to your original start position. Continue back and forth for several repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lateral_Bound/0.jpg','exercisedb',true),('Lateral_Box_Jump','Lateral Box Jump','aductores',ARRAY['abductores','pantorrillas','glúteos','isquiotibiales','cuádriceps'],'otro','plyometrics',ARRAY['Assume a comfortable standing position, with a short box positioned next to you. This will be your starting position.','Quickly dip into a quarter squat to initiate the stretch reflex, and immediately reverse direction to jump up and to the side.','Bring your knees high enough to ensure your feet have good clearance over the box.','Land on the center of the box, using your legs to absorb the impact.','Carefully jump down to the other side of the box, and continue going back and forth for several repetitions.'],'Assume a comfortable standing position, with a short box positioned next to you. This will be your starting position. Quickly dip into a quarter squat to initiate the stretch reflex, and immediately reverse direction to jump up and to the side. Bring your knees high enough to ensure your feet have good clearance over the box. Land on the center of the box, using your legs to absorb the impact. Carefully jump down to the other side of the box, and continue going back and forth for several repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lateral_Box_Jump/0.jpg','exercisedb',true),('Lateral_Cone_Hops','Lateral Cone Hops','aductores',ARRAY['abductores','pantorrillas','glúteos','isquiotibiales','cuádriceps'],'otro','plyometrics',ARRAY['Position a number of cones in a row several feet apart.','Stand next to the end of the cones, facing 90 degrees to the direction of travel. This will be your starting position.','Begin the jump by dipping with the knees to initiate a stretch reflex, and immediately reverse direction to push off the ground, jumping up and sideways over the cone.','Use your legs to absorb impact upon landing, and rebound into the next jump, continuing down the row of cones.'],'Position a number of cones in a row several feet apart. Stand next to the end of the cones, facing 90 degrees to the direction of travel. This will be your starting position. Begin the jump by dipping with the knees to initiate a stretch reflex, and immediately reverse direction to push off the ground, jumping up and sideways over the cone. Use your legs to absorb impact upon landing, and rebound into the next jump, continuing down the row of cones.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lateral_Cone_Hops/0.jpg','exercisedb',true),('Lateral_Raise_-_With_Bands','Lateral Raise - With Bands','hombros',ARRAY[]::text[],'bandas elásticas','strength',ARRAY['To begin, stand on an exercise band so that tension begins at arm''''s length. Grasp the handles using a pronated (palms facing your thighs) grip that is slightly less than shoulder width. The handles should be resting on the sides of your thighs. Your arms should be extended with a slight bend at the elbows and your back should be straight. This will be your starting position.','Use your side shoulders to lift the handles to the sides as you exhale. Continue to lift the handles until they are slightly above parallel. Tip: As you lift the handles, slightly tilt the hand as if you were pouring water and keep your arms extended. Also, keep your torso stationary and pause for a second at the top of the movement.','Lower the handles back down slowly to the starting position. Inhale as you perform this portion of the movement.','Repeat for the recommended amount of repetitions.'],'To begin, stand on an exercise band so that tension begins at arm''s length. Grasp the handles using a pronated (palms facing your thighs) grip that is slightly less than shoulder width. The handles should be resting on the sides of your thighs. Your arms should be extended with a slight bend at the elbows and your back should be straight. This will be your starting position. Use your side shoulders to lift the handles to the sides as you exhale. Continue to lift the handles until they are slightly above parallel. Tip: As you lift the handles, slightly tilt the hand as if you were pouring water and keep your arms extended. Also, keep your torso stationary and pause for a second at the top of the movement. Lower the handles back down slowly to the starting position. Inhale as you perform this portion of the movement. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lateral_Raise_-_With_Bands/0.jpg','exercisedb',true),('Latissimus_Dorsi-SMR','Latissimus Dorsi-SMR','dorsales',ARRAY[]::text[],'foam roller','stretching',ARRAY['While lying on the floor, place a foam roll under your back and to one side, just behind your arm pit. This will be your starting position.','Keep the arm of the side being stretched behind and to the side of you as you shift your weight onto your lats, keeping your upper body off of the ground. Hold for 10-30 seconds, and switch sides.'],'While lying on the floor, place a foam roll under your back and to one side, just behind your arm pit. This will be your starting position. Keep the arm of the side being stretched behind and to the side of you as you shift your weight onto your lats, keeping your upper body off of the ground. Hold for 10-30 seconds, and switch sides.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Latissimus_Dorsi-SMR/0.jpg','exercisedb',true),('Leg-Over_Floor_Press','Leg-Over Floor Press','pecho',ARRAY['hombros','tríceps'],'kettlebells','strength',ARRAY['Lie on the floor with one kettlebell in place on your chest, holding it by the handle. Extend leg on working side over leg on non-working side.Your free arm can be extended out to your side for support.','Press the kettlebll into a locked out position.','Lower the weight until the elbow touches the ground, keeping the kettlebell above the elbow. Repeat for the desired number of repetitions.'],'Lie on the floor with one kettlebell in place on your chest, holding it by the handle. Extend leg on working side over leg on non-working side.Your free arm can be extended out to your side for support. Press the kettlebll into a locked out position. Lower the weight until the elbow touches the ground, keeping the kettlebell above the elbow. Repeat for the desired number of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg-Over_Floor_Press/0.jpg','exercisedb',true),('Leg-Up_Hamstring_Stretch','Leg-Up Hamstring Stretch','isquiotibiales',ARRAY[]::text[],NULL,'stretching',ARRAY['Lie flat on your back, bend one knee, and put that foot flat on the floor to stabilize your spine.','Extend the other leg in the air. If you''''re tight, you wont be able to straighten it. That''''s okay. Extend the knee so that the sole of the lifted foot faces the ceiling (or as close as you can get it).','Slowly straighten the legs as much as possible and then pull the leg toward your nose. Switch sides.'],'Lie flat on your back, bend one knee, and put that foot flat on the floor to stabilize your spine. Extend the other leg in the air. If you''re tight, you wont be able to straighten it. That''s okay. Extend the knee so that the sole of the lifted foot faces the ceiling (or as close as you can get it). Slowly straighten the legs as much as possible and then pull the leg toward your nose. Switch sides.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg-Up_Hamstring_Stretch/0.jpg','exercisedb',true),('Leg_Extensions','Leg Extensions','cuádriceps',ARRAY[]::text[],'máquina','strength',ARRAY['For this exercise you will need to use a leg extension machine. First choose your weight and sit on the machine with your legs under the pad (feet pointed forward) and the hands holding the side bars. This will be your starting position. Tip: You will need to adjust the pad so that it falls on top of your lower leg (just above your feet). Also, make sure that your legs form a 90-degree angle between the lower and upper leg. If the angle is less than 90-degrees then that means the knee is over the toes which in turn creates undue stress at the knee joint. If the machine is designed that way, either look for another machine or just make sure that when you start executing the exercise you stop going down once you hit the 90-degree angle.','Using your quadriceps, extend your legs to the maximum as you exhale. Ensure that the rest of the body remains stationary on the seat. Pause a second on the contracted position.','Slowly lower the weight back to the original position as you inhale, ensuring that you do not go past the 90-degree angle limit.','Repeat for the recommended amount of times.'],'For this exercise you will need to use a leg extension machine. First choose your weight and sit on the machine with your legs under the pad (feet pointed forward) and the hands holding the side bars. This will be your starting position. Tip: You will need to adjust the pad so that it falls on top of your lower leg (just above your feet). Also, make sure that your legs form a 90-degree angle between the lower and upper leg. If the angle is less than 90-degrees then that means the knee is over the toes which in turn creates undue stress at the knee joint. If the machine is designed that way, either look for another machine or just make sure that when you start executing the exercise you stop going down once you hit the 90-degree angle. Using your quadriceps, extend your legs to the maximum as you exhale. Ensure that the rest of the body remains stationary on the seat. Pause a second on the contracted position. Slowly lower the weight back to the original position as you inhale, ensuring that you do not go past the 90-degree angle limit. Repeat for the recommended amount of times.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg_Extensions/0.jpg','exercisedb',true);